{"data":{"pdfTemplatePackageSlipGet":{"id":"ad0d90a1-0f81-531c-b0ab-5c46e9ccc48c_PDFTemplatePackageSlip","htmlTemplate":"
<div class="delivery-note">
  <!-- ヘッダー -->
  <div class="dn-header">
    <div class="dn-title">納品書</div>
    <div class="dn-meta">
      <div class="dn-meta-item">
        <span class="dn-meta-label">注文日：</span>
        {{if .Order.PurchasedAt}}<span class="no-wrap">{{(.Order.PurchasedAt | InTZ "Asia/Tokyo").Format "2006/01/02"}}</span>{{end}}
      </div>
      <div class="dn-meta-item">
        <span class="dn-meta-label">注文番号：</span>
        {{if .Order.ManagementCode}}<span class="no-wrap">{{.Order.ManagementCode}}</span>{{end}}
      </div>
    </div>
  </div>

  <!-- ご請求先 / お届け先 -->
  <div class="dn-boxes">
    <div class="dn-box">
      <h3>ご請求先</h3>
      {{if .Order.BillingAddress}}
        {{if or .Order.BillingAddress.LastName .Order.BillingAddress.FirstName}}
          <div>{{.Order.BillingAddress.LastName}}{{.Order.BillingAddress.FirstName}}</div>
        {{end}}
        {{if or .Order.BillingAddress.PostalCode .Order.BillingAddress.Province .Order.BillingAddress.City .Order.BillingAddress.Address1}}
          <div>〒{{.Order.BillingAddress.PostalCode}} {{.Order.BillingAddress.Province}}{{.Order.BillingAddress.City}}{{.Order.BillingAddress.Address1}}</div>
        {{end}}
        {{if .Order.BillingAddress.Address2}}<div>{{.Order.BillingAddress.Address2}}</div>{{end}}
        {{if .Order.BillingAddress.Phone}}<div>TEL: {{.Order.BillingAddress.Phone}}</div>{{end}}
      {{end}}
    </div>
    <div class="dn-box">
      <h3>お届け先</h3>
      {{if .Order.ShippingAddress}}
        {{if or .Order.ShippingAddress.LastName .Order.ShippingAddress.FirstName}}
          <div>{{.Order.ShippingAddress.LastName}}{{.Order.ShippingAddress.FirstName}}</div>
        {{end}}
        {{if or .Order.ShippingAddress.PostalCode .Order.ShippingAddress.Province .Order.ShippingAddress.City .Order.ShippingAddress.Address1}}
          <div>〒{{.Order.ShippingAddress.PostalCode}} {{.Order.ShippingAddress.Province}}{{.Order.ShippingAddress.City}}{{.Order.ShippingAddress.Address1}}</div>
        {{end}}
        {{if .Order.ShippingAddress.Address2}}<div>{{.Order.ShippingAddress.Address2}}</div>{{end}}
        {{if .Order.ShippingAddress.Phone}}<div>TEL: {{.Order.ShippingAddress.Phone}}</div>{{end}}
      {{end}}
    </div>
  </div>

  <div class="dn-rule"></div>

  <!-- 明細 -->
  <table class="dn-table">
    <thead>
      <tr>
        <th class="dn-col-thumb"></th>
        <th class="dn-col-brand">ブランド</th>
        <th class="dn-col-name">商品名</th>
        <th class="dn-col-color">カラー/サイズ</th>
        <th class="dn-col-price">単価</th>
        <th class="dn-col-qty">数量</th>
        <th class="dn-col-subtotal">小計</th>
      </tr>
    </thead>
    <tbody>
      {{range .LineItems.Nodes}}
        {{ $oli := .OrderLineItem }}
        <tr>
          <td class="dn-col-thumb">
            {{if and $oli $oli.ProductVariant $oli.ProductVariant.FeaturedImage $oli.ProductVariant.FeaturedImage.URL}}
              <img class="dn-thumb" src="{{$oli.ProductVariant.FeaturedImage.URL}}" alt="">
            {{end}}
          </td>
          <td class="dn-col-brand">{{if and $oli $oli.ProductVariant $oli.ProductVariant.Product}}{{$oli.ProductVariant.Product.ProductVendor}}{{end}}</td>
          <td class="dn-col-name">
            {{if $oli.ProductTitle}}<span class="dn-product-title">{{$oli.ProductTitle}}</span>{{end}}
          </td>
          <td class="dn-col-color">{{if $oli.ProductVariantTitle}}{{$oli.ProductVariantTitle}}{{end}}</td>
          <td class="dn-col-price">{{if $oli.UnitPrice}}{{FormatWithComma $oli.UnitPrice.Amount}}{{end}}</td>
          <td class="dn-col-qty">{{if $oli.CurrentQuantity}}{{$oli.CurrentQuantity}}{{end}}</td>
          <td class="dn-col-subtotal">{{if $oli.CurrentPrice}}{{FormatWithComma $oli.CurrentPrice.Amount}}{{end}}</td>
        </tr>
      {{end}}
    </tbody>
  </table>

  <!-- 注記 -->
  <div class="dn-notes">
    {{if .Order.PaymentMethods}}
      {{with index .Order.PaymentMethods 0}}
        {{if .Name}}<div>お支払い方法：{{.Name}}</div>{{end}}
      {{end}}
    {{else}}
      <div>お支払い方法：—</div>
    {{end}}
  </div>
</div>

<style>
  .delivery-note { font-family: "Noto Sans JP","Noto Sans CJK JP",sans-serif; font-size: 13px; color: #111; }
  .no-wrap { white-space: nowrap; }

  .dn-header { border-bottom: 2px solid #111; padding-bottom: 8px; margin-bottom: 12px; }
  .dn-title { font-size: 18px; font-weight: 700; letter-spacing: .5px; }

  .dn-meta { display: flex; gap: 24px; align-items: baseline; }
  .dn-meta-item { display: inline-flex; align-items: baseline; gap: 6px; white-space: nowrap; min-width: 0; }
  .dn-meta-label { color: #666; }

  .dn-boxes { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 12px; }
  .dn-box { border: 1px solid #cfcfcf; min-height: 96px; padding: 10px 12px; }
  .dn-box h3 { margin: 0 0 6px; font-size: 12px; font-weight: 700; }

  .dn-rule { height: 1px; background: #999; margin: 14px 0; opacity: .6; }

  .dn-table { width: 100%; border-collapse: collapse; }
  .dn-table thead th {
    background: #f6f6f6;
    border-top: 1px solid #cfcfcf;
    border-bottom: 1px solid #cfcfcf;
    padding: 8px;
    font-weight: 700;
    font-size: 12px;
  }
  .dn-table tbody td { border-bottom: 1px solid #e6e6e6; padding: 8px; vertical-align: middle; }

  .dn-col-thumb { width: 40px; }
  .dn-thumb { width: 32px; height: 32px; object-fit: cover; border: 1px solid #e0e0e0; }
  .dn-col-brand { width: 110px; }
  .dn-col-name { width: 40%; white-space: normal; word-break: break-word; overflow-wrap: anywhere; }
  .dn-product-title { display: inline; }
  .dn-col-color { width: 160px; text-align: center; }
  .dn-col-price, .dn-col-qty, .dn-col-subtotal { width: 90px; text-align: right; }

  .dn-notes { margin-top: 18px; font-size: 11px; color: #444; }

  @media print {
    .dn-table thead { display: table-header-group; }
    .dn-table tr { page-break-inside: avoid; break-inside: avoid; }
  }
</style>
","__typename":"PDFTemplatePackageSlip"}}}

